# Production-grade prompt optimization for cricket commentary generation
from transformers import pipeline
import json

def optimized_cricket_commentary(match_state: dict, budget_tokens=150) -> str:
    """
    Production system: Generates cricket commentary with cost optimization.
    Demonstrates few-shot learning at scale with token budgeting.
    """

    # Few-shot examples selected dynamically based on match_state
    few_shot_examples = [
        {
            "situation": "Batsman vs Pace Bowler",
            "example": "Sharma faces Anderson with aggressive field placement. Short pitched delivery, Sharma pulls for four! Excellent timing on the back foot."
        },
        {
            "situation": "Death Overs",
            "example": "Final over, 8 runs needed. Pant walks down the pitch, yorker length, dug out for a single. Drama unfolds!"
        }
    ]

    # Select relevant few-shot examples to reduce token usage
    selected_examples = [e for e in few_shot_examples 
                         if e["situation"] in match_state.get("phase", "")]

    # Build optimized prompt with explicit structure
    prompt = f"""Generate cricket match commentary.

Context:
- Batsman: {match_state['batsman']}
- Bowler: {match_state['bowler']}
- Phase: {match_state['phase']}
- Run Rate: {match_state['run_rate']}

Examples of good commentary:
{chr(10).join([f"• {e['example']}" for e in selected_examples])}

Generate 1-2 sentences of live commentary:"""

    # Token counting for budget management
    estimated_tokens = len(prompt.split()) * 1.3
    if estimated_tokens > budget_tokens:
        prompt = prompt[:int(len(prompt) * (budget_tokens / estimated_tokens))]

    return prompt

# Usage in production pipeline
match_data = {
    "batsman": "Kohli",
    "bowler": "Cummins",
    "phase": "Powerplay",
    "run_rate": 8.5
}

optimized_prompt = optimized_cricket_commentary(match_data)
print(optimized_prompt)
